226: 		pluginMap[plugin.id].settingsRoute = plugin.settingsRoute;
227: 		pluginMap[plugin.id].license = plugin.license;
228: 
229: 		// If package.json defines a version to use, stick to that
230: 		if (dependencies.hasOwnProperty(plugin.id) && semver.valid(dependencies[plugin.id])) {
231: 			pluginMap[plugin.id].latest = dependencies[plugin.id];
232: 		} else {
233: 			pluginMap[plugin.id].latest = pluginMap[plugin.id].latest || plugin.version;
234: 		}
235: 		pluginMap[plugin.id].outdated = semver.gt(pluginMap[plugin.id].latest, pluginMap[plugin.id].version);
236: 	});
